import { expect } from '../testing/expect';
import { describe, test } from '../testing/registry';
import { createRuntimeProbabilityRouteDecision } from '../probability-routing';

describe('runtime probability routing', () => {
  test('lifts route mass witnesses into runtime probability traces', () => {
    const decision = createRuntimeProbabilityRouteDecision({
      certificateId: 'route-hot-chat',
      target: 'aeon-flux:navigation',
      routes: [
        { route: '/chat', count: 8 },
        { route: '/settings', count: 1 },
        { route: '/tools', count: 1 },
      ],
      policy: {
        minObservations: 10,
        minConcentrationBps: 7_000,
        residualBudget: 2,
      },
    });

    expect(decision.selection.selected[0]?.route).toBe('/chat');
    expect(decision.selection.selected[0]?.decision).toBe('reuse');
    expect(decision.trace.residualTotal).toBeGreaterThan(0);
    expect(decision.observer.decision).toBe('shrink-horizon');
  });
});
